package com.example.capstonepoc;

import dev.langchain4j.data.embedding.Embedding;
import dev.langchain4j.data.segment.TextSegment;
import dev.langchain4j.model.ollama.OllamaEmbeddingModel;
import dev.langchain4j.model.output.Response;
import java.time.Duration;

public class OllamaEmbedding {


  public static final OllamaEmbeddingModel embeddingModel = OllamaEmbeddingModel.builder()
    .baseUrl("http://localhost:11434")
    .modelName("nomic-embed-text")
    .timeout(Duration.ofSeconds(60))
    .logRequests(true)  // Helpful for debugging your POC
    .logResponses(true)
    .build();

  public float[] getEmbedding(String text) {
    try {
      TextSegment textSegment = TextSegment.from(text);
      Response<Embedding> response = embeddingModel.embed(textSegment);
      Embedding embedding = response.content();
      float[] vector = embedding.vector();
      if (vector.length == 768) {
        return vector;
      }
    } catch (Exception e) {
      System.err.println("FAILED: Ensure Ollama is running and 'nomic-embed-text' is pulled.");
      e.printStackTrace();
    }
    return new float[0];
  }

}

package com.example.capstonepoc;

import dev.langchain4j.data.embedding.Embedding;
import dev.langchain4j.data.segment.TextSegment;
import dev.langchain4j.model.ollama.OllamaEmbeddingModel;
import dev.langchain4j.model.output.Response;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

/**
 * Service for generating text embeddings using Ollama.
 * Uses the OllamaEmbeddingModel bean configured in OllamaConfig.
 */
@Service
public class OllamaEmbedding {
  private static final Logger logger = LoggerFactory.getLogger(OllamaEmbedding.class);
  private static final int EXPECTED_VECTOR_LENGTH = 768;

  @Autowired
  private OllamaEmbeddingModel embeddingModel;

  /**
   * Gets embedding vector for the given text.
   *
   * @param text the text to embed
   * @return float array representing the embedding (768 dimensions) or empty array on error
   */
  public float[] getEmbedding(String text) {
    try {
      TextSegment textSegment = TextSegment.from(text);
      Response<Embedding> response = embeddingModel.embed(textSegment);
      Embedding embedding = response.content();
      float[] vector = embedding.vector();
      if (vector.length == EXPECTED_VECTOR_LENGTH) {
        logger.debug("Successfully generated embedding for text of length: {}", text.length());
        return vector;
      } else {
        logger.warn("Unexpected vector length: {}, expected: {}", vector.length, EXPECTED_VECTOR_LENGTH);
      }
    } catch (Exception e) {
      logger.error("FAILED: Ensure Ollama is running and 'nomic-embed-text' is pulled.", e);
    }
    return new float[0];
  }
}

package com.example.capstonepoc.controller;

import com.example.capstonepoc.OllamaEmbedding;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.Map;

/**
 * REST Controller for embedding operations.
 * Provides endpoints for generating text embeddings.
 */
@RestController
@RequestMapping("/api/embeddings")
public class EmbeddingController {
  private static final Logger logger = LoggerFactory.getLogger(EmbeddingController.class);

  @Autowired
  private OllamaEmbedding ollamaEmbedding;

  /**
   * Health check endpoint.
   *
   * @return status response
   */
  @GetMapping("/health")
  public ResponseEntity<Map<String, String>> health() {
    Map<String, String> response = new HashMap<>();
    response.put("status", "UP");
    response.put("message", "Embedding service is running");
    return ResponseEntity.ok(response);
  }

  /**
   * Generate embedding for given text.
   *
   * @param request containing the text to embed
   * @return embedding response with vector and metadata
   */
  @PostMapping("/generate")
  public ResponseEntity<Map<String, Object>> generateEmbedding(@RequestBody EmbeddingRequest request) {
    Map<String, Object> response = new HashMap<>();

    try {
      float[] embedding = ollamaEmbedding.getEmbedding(request.getText());

      if (embedding.length == 0) {
        logger.warn("Failed to generate embedding for text: {}", request.getText());
        response.put("success", false);
        response.put("error", "Failed to generate embedding. Ensure Ollama is running.");
        return ResponseEntity.badRequest().body(response);
      }

      response.put("success", true);
      response.put("text", request.getText());
      response.put("embedding_length", embedding.length);
      response.put("embedding", embedding);
      return ResponseEntity.ok(response);
    } catch (Exception e) {
      logger.error("Error generating embedding", e);
      response.put("success", false);
      response.put("error", e.getMessage());
      return ResponseEntity.internalServerError().body(response);
    }
  }

  /**
   * Request body for embedding generation.
   */
  public static class EmbeddingRequest {
    private String text;

    public EmbeddingRequest() {}

    public EmbeddingRequest(String text) {
      this.text = text;
    }

    public String getText() {
      return text;
    }

    public void setText(String text) {
      this.text = text;
    }
  }
}
